const statusConfig = {
  Shipped:    { textColor: "text-blue-600",  bg: "bg-blue-50",   border: "border-blue-200", icon: "🚚", steps: 2 },
  Processing: { textColor: "text-amber-600", bg: "bg-amber-50",  border: "border-amber-200", icon: "⚙️", steps: 1 },
  Delivered:  { textColor: "text-emerald-600", bg: "bg-emerald-50", border: "border-emerald-200", icon: "✅", steps: 4 },
  Cancelled:  { textColor: "text-red-600",   bg: "bg-red-50",    border: "border-red-200", icon: "✕",  steps: 0 },
};

const deptConfig = {
  ICU:            { bg: "bg-red-500",    text: "text-white" },
  Radiology:      { bg: "bg-violet-500", text: "text-white" },
  "General Ward": { bg: "bg-sky-500",    text: "text-white" },
  Cardiology:     { bg: "bg-rose-500",   text: "text-white" },
  Diagnostics:    { bg: "bg-amber-500",  text: "text-white" },
  Surgery:        { bg: "bg-emerald-500",text: "text-white" },
};

const PAGE_SIZE = 6;

function ShippingTracker({ status }) {
  const steps = ["Order Placed", "Processing", "Shipped", "Delivered"];
  const activeStep = statusConfig[status]?.steps ?? 0;

  if (status === "Cancelled") return (
    <div className="flex items-center gap-2 mt-1">
      <span className="w-2 h-2 rounded-full bg-red-400 inline-block" />
      <span className="text-xs text-red-500 font-bold">Order Cancelled</span>
    </div>
  );

  return (
    <div className="flex items-center mt-2">
      {steps.map((step, i) => (
        <div key={step} className={`flex items-center ${i < steps.length - 1 ? "flex-1" : ""}`}>
          <div className="flex flex-col items-center">
            <div className={`w-5 h-5 rounded-full flex items-center justify-center text-xs font-bold border-2 transition-all
              ${i <= activeStep ? "bg-blue-600 border-blue-600 text-white" : "bg-slate-100 border-slate-300 text-slate-400"}`}>
              {i < activeStep ? "✓" : i + 1}
            </div>
            <span className={`text-center leading-tight mt-1 ${i <= activeStep ? "text-blue-700 font-bold" : "text-slate-400 font-normal"}`}
              style={{ fontSize: "9px", maxWidth: "44px" }}>{step}</span>
          </div>
          {i < steps.length - 1 && (
            <div className={`flex-1 h-0.5 mx-1 mb-4 rounded ${i < activeStep ? "bg-blue-600" : "bg-slate-200"}`} />
          )}
        </div>
      ))}
    </div>
  );
}

export default function OrdersPage() {
  const [filter, setFilter] = useState("All");
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState("");

  const totalRevenue = orders
    .filter(o => o.shippingStatus !== "Cancelled")
    .reduce((sum, o) => sum + parseInt(o.equipment.price.replace(/[₹,]/g, "")), 0);

  const filtered = orders.filter(o => {
    const matchFilter = filter === "All" || o.shippingStatus === filter;
    const q = search.toLowerCase();
    const matchSearch = !q ||
      o.id.toLowerCase().includes(q) ||
      o.hospital.toLowerCase().includes(q) ||
      o.equipment.name.toLowerCase().includes(q) ||
      o.equipment.department.toLowerCase().includes(q) ||
      o.equipment.category.toLowerCase().includes(q);
    return matchFilter && matchSearch;
  });

  const totalPages = Math.ceil(filtered.length / PAGE_SIZE);
  const paginated = filtered.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);

  const handleFilter = (f) => { setFilter(f); setPage(1); };
  const handleSearch = (e) => { setSearch(e.target.value); setPage(1); };

  const stats = [
    { label: "Total Orders", value: orders.length,                                                          color: "text-blue-800",    bg: "bg-blue-50",   border: "border-blue-100" },
    { label: "Active",       value: orders.filter(o => ["Shipped","Processing"].includes(o.shippingStatus)).length, color: "text-amber-700",   bg: "bg-amber-50",  border: "border-amber-100" },
    { label: "Delivered",    value: orders.filter(o => o.shippingStatus === "Delivered").length,             color: "text-emerald-700", bg: "bg-emerald-50",border: "border-emerald-100" },
    { label: "Revenue",      value: `₹${(totalRevenue / 1000).toFixed(0)}K`,                                color: "text-violet-700",  bg: "bg-violet-50", border: "border-violet-100" },
  ];

  return (
    <div className="min-h-screen relative bg-gradient-to-br from-[#0f172a] via-[#1e3a8a] to-[#60a5fa]">
      {/* ── NAV ── */}
      <div className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-4xl mx-auto px-5 py-3 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="rounded-lg px-3 py-1.5" style={{ background: "linear-gradient(135deg,#1e3a8a,#2563eb)" }}>
              <span className="text-white font-bold text-sm">Med<span className="text-blue-300">Track</span></span>
            </div>
          </div>
          <div className="bg-blue-50 rounded-full px-3 py-1">
            <span className="text-blue-800 text-xs font-bold"> MedSupply Corp</span>
          </div>
        </div>
      </div>

      <div className="max-w-4xl mx-auto px-5 py-6">

        {/* ── STATS ── */}
        <div className="grid grid-cols-4 gap-3 mb-6">
          {stats.map(s => (
            <div key={s.label} className={`${s.bg} ${s.border} border rounded-xl px-4 py-3`}>
              <p className={`${s.color} text-2xl font-extrabold m-0`}>{s.value}</p>
              <p className={`${s.color} opacity-60 text-xs font-bold mt-0.5 uppercase tracking-wide`}>{s.label}</p>
            </div>
          ))}
        </div>

        {/* ── SEARCH + FILTERS ── */}
        <div className="flex flex-wrap gap-2 items-center mb-5">
          <input
            value={search} onChange={handleSearch}
            placeholder="🔍  Search hospital, equipment, dept..."
            className="border border-slate-200 rounded-full px-4 py-1.5 text-xs outline-none bg-white text-slate-700 w-60"
            style={{ fontFamily: "inherit" }}
          />
          {["All","Processing","Shipped","Delivered","Cancelled"].map(f => (
            <button key={f} onClick={() => handleFilter(f)}
              className={`px-4 py-1.5 text-xs font-bold rounded-full border transition-all cursor-pointer
                ${filter === f ? "bg-blue-700 text-white border-blue-700" : "bg-white text-slate-500 border-slate-200 hover:border-blue-300"}`}
              style={{ fontFamily: "inherit" }}>
              {f}
            </button>
          ))}
          <span className="ml-auto text-xs text-slate-400 font-semibold">{filtered.length} orders</span>
        </div>

        {/* ── ORDER CARDS ── */}
        <div className="flex flex-col gap-4">
          {paginated.length === 0 ? (
            <div className="bg-white rounded-2xl p-12 text-center text-slate-400 text-sm">No orders match your search.</div>
          ) : paginated.map(order => {
            const sc = statusConfig[order.shippingStatus];
            const dc = deptConfig[order.equipment.department] || { bg: "bg-slate-500", text: "text-white" };

            return (
              <div key={order.id} className="bg-white rounded-2xl overflow-hidden border border-slate-200 shadow-sm">

                {/* Hospital Banner */}
                <div className="relative h-16 overflow-hidden">
                  <img src={order.hospitalImg} alt={order.hospital}
                    className="w-full h-full object-cover brightness-50"
                    onError={e => { e.target.style.display = "none"; }} />
                  <div className="absolute inset-0" style={{ background: "linear-gradient(90deg,rgba(15,23,42,0.85),rgba(15,23,42,0.3))" }} />
                  <div className="absolute inset-0 flex items-center justify-between px-4">
                    <div>
                      <p className="text-blue-300 font-bold uppercase tracking-widest" style={{ fontSize: "8px" }}>
                         {order.supplierName} &nbsp;→&nbsp; Supplying to
                      </p>
                      <p className="text-white font-extrabold text-base mt-0.5"> {order.hospital}</p>
                    </div>
                    <div className={`${sc.bg} ${sc.border} border rounded-full px-3 py-1 flex items-center gap-1.5`}>
                      <span className="text-xs">{sc.icon}</span>
                      <span className={`${sc.textColor} text-xs font-extrabold`}>{order.shippingStatus}</span>
                    </div>
                  </div>
                </div>

                {/* Body */}
                <div className="flex border-t border-slate-100">
                  {/* Image */}
                  <div className="w-40 flex-shrink-0 relative overflow-hidden">
                    <img src={order.equipment.img} alt={order.equipment.name}
                      className="w-full h-36 object-cover block"
                      onError={e => { e.target.style.background = "#f1f5f9"; }} />
                    <span className={`absolute bottom-2 left-2 ${dc.bg} ${dc.text} text-xs font-extrabold px-2 py-0.5 rounded-full uppercase tracking-wide`} style={{ fontSize: "8px" }}>
                      {order.equipment.category}
                    </span>
                  </div>

                  {/* Details */}
                  <div className="flex-1 px-4 py-3 border-l border-slate-100">
                    <div className="flex justify-between items-start mb-1.5">
                      <span className="bg-slate-50 border border-slate-200 text-slate-400 text-xs font-bold px-2 py-0.5 rounded" style={{ fontSize: "10px" }}>
                        {order.id}
                      </span>
                      <span className="text-slate-900 font-black text-lg">{order.equipment.price}</span>
                    </div>

                    <p className="text-slate-900 font-extrabold text-sm mb-2 leading-tight">{order.equipment.name}</p>

                    <div className="mb-3">
                      <span className={`${dc.bg} ${dc.text} text-xs font-bold px-2.5 py-0.5 rounded-full`} style={{ fontSize: "10px" }}>
                        {order.equipment.department}
                      </span>
                    </div>

                    <div className="grid grid-cols-3 gap-2 bg-slate-50 border border-slate-100 rounded-xl p-2.5">
                      {[
                        { label: "Ordered Date", value: order.orderedDate },
                        { label: "Est. Delivery", value: order.estimatedDelivery },
                        { label: "Tracking No.", value: order.trackingNo, mono: true },
                      ].map(item => (
                        <div key={item.label}>
                          <p className="text-slate-400 font-bold uppercase tracking-wide mb-0.5" style={{ fontSize: "8px" }}>{item.label}</p>
                          <p className={`font-bold text-slate-800 ${item.mono ? "font-mono text-blue-600" : ""}`} style={{ fontSize: "11px" }}>
                            {item.icon} {item.value}
                          </p>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                {/* Tracker Footer */}
                <div className="px-4 pb-3 pt-2 border-t border-slate-100 bg-slate-50">
                  <p className="text-slate-400 font-bold uppercase tracking-widest mb-1" style={{ fontSize: "8px" }}>Shipping Progress</p>
                  <ShippingTracker status={order.shippingStatus} />
                </div>
              </div>
            );
          })}
        </div>

        {/* ── PAGINATION ── */}
        {totalPages > 1 && (
          <div className="flex justify-center items-center gap-2 mt-6 flex-wrap">
            <button onClick={() => setPage(p => Math.max(1, p - 1))} disabled={page === 1}
              className={`px-4 py-1.5 text-xs font-bold rounded-full border transition-all
                ${page === 1 ? "bg-white text-slate-300 border-slate-200 cursor-not-allowed" : "bg-white text-slate-600 border-slate-200 hover:border-blue-400 cursor-pointer"}`}
              style={{ fontFamily: "inherit" }}>← Prev</button>

            {Array.from({ length: totalPages }, (_, i) => i + 1).map(p => (
              <button key={p} onClick={() => setPage(p)}
                className={`w-8 h-8 text-xs font-bold rounded-full border cursor-pointer transition-all
                  ${page === p ? "bg-blue-700 text-white border-blue-700" : "bg-white text-slate-600 border-slate-200 hover:border-blue-400"}`}
                style={{ fontFamily: "inherit" }}>{p}</button>
            ))}

            <button onClick={() => setPage(p => Math.min(totalPages, p + 1))} disabled={page === totalPages}
              className={`px-4 py-1.5 text-xs font-bold rounded-full border transition-all
                ${page === totalPages ? "bg-white text-slate-300 border-slate-200 cursor-not-allowed" : "bg-white text-slate-600 border-slate-200 hover:border-blue-400 cursor-pointer"}`}
              style={{ fontFamily: "inherit" }}>Next →</button>
          </div>
        )}

        {totalPages > 1 && (
          <p className="text-center text-slate-400 text-xs font-semibold mt-2">
            Showing {(page-1)*PAGE_SIZE+1}–{Math.min(page*PAGE_SIZE, filtered.length)} of {filtered.length} orders
          </p>
        )}
      </div>
    </div>
  );
}
